import{_ as e,o as i,c as a,ad as s}from"./chunks/framework.DdcUsuRQ.js";const u=JSON.parse('{"title":"WCAG 2.1","description":"The luminance-ratio contrast algorithm iridis uses by default. Rec. 709 coefficients, the 0.05 flare term, and AA/AAA threshold tables for text and UI.","frontmatter":{"title":"WCAG 2.1","description":"The luminance-ratio contrast algorithm iridis uses by default. Rec. 709 coefficients, the 0.05 flare term, and AA/AAA threshold tables for text and UI.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/wcag"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/wcag"}],["meta",{"property":"og:title","content":"WCAG 2.1: iridis"}],["meta",{"property":"og:description","content":"The luminance-ratio contrast algorithm iridis uses by default. Rec. 709 coefficients, the 0.05 flare term, and AA/AAA threshold tables for text and UI."}],["meta",{"name":"twitter:title","content":"WCAG 2.1: iridis"}],["meta",{"name":"twitter:description","content":"The luminance-ratio contrast algorithm iridis uses by default. Rec. 709 coefficients, the 0.05 flare term, and AA/AAA threshold tables for text and UI."}],["meta",{"name":"description","content":"The luminance-ratio contrast algorithm iridis uses by default. Rec. 709 coefficients, the 0.05 flare term, and AA/AAA threshold tables for text and UI."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"WCAG 2.1\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/wcag\\"}]}"]]},"headers":[],"relativePath":"reference/wcag.md","filePath":"reference/wcag.md","lastUpdated":1779033869000}'),r={name:"reference/wcag.md"};function n(o,t,d,c,l,h){return i(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="wcag-2-1" tabindex="-1">WCAG 2.1 <a class="header-anchor" href="#wcag-2-1" aria-label="Permalink to &quot;WCAG 2.1&quot;">​</a></h1><p>The Web Content Accessibility Guidelines 2.1 contrast algorithm produces a single ratio between two colors based on their relative luminance. It is the default contrast metric used by <code>enforce:contrast</code>.</p><h2 id="relative-luminance" tabindex="-1">Relative luminance <a class="header-anchor" href="#relative-luminance" aria-label="Permalink to &quot;Relative luminance&quot;">​</a></h2><p>Each color&#39;s relative luminance Y is the dot product of its linear sRGB channels with the Rec. 709 luminance coefficients:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>Y = 0.2126 · R_linear + 0.7152 · G_linear + 0.0722 · B_linear</span></span></code></pre></div><p>The coefficients reflect the photopic response of the human eye to the sRGB primaries: green dominates, red contributes about a third as much, blue contributes least.</p><p>The linear values are produced by the standard sRGB inverse transfer function:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>v_linear = v / 12.92                          if v ≤ 0.04045</span></span>
<span class="line"><span>         = ((v + 0.055) / 1.055) ^ 2.4        otherwise</span></span></code></pre></div><p>Both <code>Luminance</code> (<code>packages/core/src/math/Luminance.ts</code>) and <code>ContrastWcag21</code> (<code>packages/core/src/math/ContrastWcag21.ts</code>) inline this decode rather than calling <code>srgbToLinear</code>, since the call frequency is high enough that the indirection is measurable.</p><h2 id="contrast-ratio" tabindex="-1">Contrast ratio <a class="header-anchor" href="#contrast-ratio" aria-label="Permalink to &quot;Contrast ratio&quot;">​</a></h2><p>Given two relative luminances Y₁ and Y₂:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>ratio = (max(Y₁, Y₂) + 0.05) / (min(Y₁, Y₂) + 0.05)</span></span></code></pre></div><p>The <code>+ 0.05</code> flare term models ambient screen reflectance and prevents the ratio from going to infinity when one of the colors is pure black. The result lies in <code>[1, 21]</code>, 1:1 for two identical colors, 21:1 for pure black on pure white.</p><p>The ratio is symmetric. WCAG 2.1 does not distinguish text from background.</p><h2 id="thresholds" tabindex="-1">Thresholds <a class="header-anchor" href="#thresholds" aria-label="Permalink to &quot;Thresholds&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Surface</th><th>Ratio</th><th>Level</th></tr></thead><tbody><tr><td>Body text under 18 pt (or under 14 pt bold)</td><td>4.5 : 1</td><td>AA</td></tr><tr><td>Large text at or above 18 pt (or 14 pt bold)</td><td>3.0 : 1</td><td>AA</td></tr><tr><td>Body text</td><td>7.0 : 1</td><td>AAA</td></tr><tr><td>Large text</td><td>4.5 : 1</td><td>AAA</td></tr><tr><td>Non-text UI components, focus indicators</td><td>3.0 : 1</td><td>AA</td></tr></tbody></table><p>Logos, decorative imagery, and disabled states are exempt from the contrast requirements.</p><h2 id="math-primitive" tabindex="-1">Math primitive <a class="header-anchor" href="#math-primitive" aria-label="Permalink to &quot;Math primitive&quot;">​</a></h2><p><code>contrastWcag21</code> is exported as a singleton from <code>@studnicky/iridis</code> (<code>packages/core/src/math/ContrastWcag21.ts</code>) and called directly:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);">import</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> {</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> contrastWcag21 </span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">}</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);"> from</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;@studnicky/iridis&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);">const</span><span style="--shiki-light:var(--iridis-syntax-constant);--shiki-dark:var(--iridis-syntax-constant);"> ratio</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);"> =</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> contrastWcag21</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">.</span><span style="--shiki-light:var(--iridis-syntax-function);--shiki-dark:var(--iridis-syntax-function);">apply</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">(</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);">foreground</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> background</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">);</span></span></code></pre></div><p>Both arguments are <code>ColorRecord</code> instances. The primitive reads the <code>rgb</code> field of each (sRGB-safe, gamut-mapped if the source OKLCH lay outside sRGB) and returns a number on <code>[1, 21]</code>.</p><h2 id="where-it-appears" tabindex="-1">Where it appears <a class="header-anchor" href="#where-it-appears" aria-label="Permalink to &quot;Where it appears&quot;">​</a></h2><ul><li><code>enforce:contrast</code> (<code>packages/core/src/tasks/enforce/EnforceContrast.ts</code>) walks <code>input.roles.contrastPairs</code> and <code>input.contrast.extra</code>. For each pair whose <code>algorithm</code> is <code>&#39;wcag21&#39;</code> (the default) it calls <code>contrastWcag21.apply(fg, bg)</code> and lifts the foreground&#39;s L coordinate in OKLCH until the configured <code>minRatio</code> is met.</li><li><code>enforce:wcagAA</code> and <code>enforce:wcagAAA</code> in the contrast plugin (<code>packages/contrast/src/tasks/</code>) are convenience wrappers that apply the AA and AAA threshold tables to declared pairs without each pair having to repeat the ratio.</li><li><code>enforce:cvdSimulate</code> re-evaluates the same <code>contrastWcag21</code> math against simulated protanopia, deuteranopia, and tritanopia versions of each pair and records warnings when the simulated ratio drops more than 1.0 below the original.</li></ul>`,23)])])}const m=e(r,[["render",n]]);export{u as __pageData,m as default};
